SELECT SUM(positions_created) AS total_positions
FROM annual_position_creation
WHERE year = 2017 AND sector = 'education';

SELECT SUM(positions_created) AS total_positions
FROM annual_position_creation
WHERE sector = 'healthcare' AND funding_source = 'government' AND year = 2016;

SELECT year, SUM(total_created) AS total_positions_created
FROM total_positions
GROUP BY year;

SELECT SUM(positions_created) AS total_positions_created
     FROM annual_position_creation
     WHERE region_id = (SELECT region_id FROM regions WHERE region_name = 'BARMM');

SELECT SUM(positions_created) AS total_positions_created
FROM annual_position_creation
WHERE year = 2023;

SELECT total_created
FROM total_positions
WHERE region_id = 1 AND year = 2017;

SELECT MAX(positions_created) AS max_positions_created
FROM annual_position_creation
WHERE sector = 'healthcare';

SELECT year, unfilled_count 
FROM unfilled_positions 
WHERE unfilled_count > 50;

SELECT sector, SUM(unfilled_count) AS total_unfilled
FROM unfilled_positions
GROUP BY sector;

SELECT SUM(unfilled_count) AS total_unfilled_positions
FROM unfilled_positions
WHERE sector = 'education' AND funding_source = 'private sector' AND year = 2017;

SELECT AVG(utilization_percent) AS average_utilization
   FROM utilization_rates
   WHERE year = 2016;

SELECT utilization_percent
FROM utilization_rates
WHERE sector = 'education' AND funding_source = 'private sector';

SELECT policy_name, budget
FROM workforce_policies
WHERE status = 'active';

SELECT AVG(utilization_percent) AS average_utilization
FROM utilization_rates
WHERE year = 2016 AND sector = 'healthcare' AND funding_source = 'government';

SELECT year, SUM(positions_created) AS total_positions_created
FROM annual_position_creation
GROUP BY year;
